// --- PKCE Utilities ---

// Generates a random string suitable for state and code_verifier
function generateRandomString(length) {
    const charset = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789";
    let result = "";
    const randomValues = new Uint32Array(length);
    window.crypto.getRandomValues(randomValues);
    for (let i = 0; i < length; i++) {
        result += charset[randomValues[i] % charset.length];
    }
    return result;
}

// SHA256 hash function
async function sha256(plain) {
    const encoder = new TextEncoder();
    const data = encoder.encode(plain);
    const hashBuffer = await crypto.subtle.digest("SHA-256", data);
    return hashBuffer;
}

// Base64Url encode function
function base64urlencode(buffer) {
    // Converts the ArrayBuffer to string and then Base64Url encodes it.
    // Replace '+' with '-', '/' with '_', and remove trailing '='
    return btoa(String.fromCharCode.apply(null, new Uint8Array(buffer)))
        .replace(/\+/g, "-")
        .replace(/\//g, "_")
        .replace(/=+$/, "");
}

// Generates PKCE code_challenge from code_verifier
async function pkce_challenge_from_verifier(v) {
    const hashed = await sha256(v);
    return base64urlencode(hashed);
}

// --- OAuth Flow Functions ---

/**
 * Initiates the OAuth 2.0 Authorization Code Flow.
 * Generates PKCE verifier, challenge, and state, then redirects to the authorization server.
 */
async function login() {
    const codeVerifier = generateRandomString(128);
    const codeChallenge = await pkce_challenge_from_verifier(codeVerifier);
    const state = generateRandomString(32);

    sessionStorage.setItem("pkce_code_verifier", codeVerifier);
    sessionStorage.setItem("oauth_state", state);

    const params = new URLSearchParams({
        response_type: "code",
        client_id: oauthConfig.clientId,
        redirect_uri: oauthConfig.redirectUri,
        scope: oauthConfig.scope,
        state: state,
        code_challenge: codeChallenge,
        code_challenge_method: "S256",
    });

    window.location.href = `${oauthConfig.authorizationEndpoint}?${params.toString()}`;
}

/**
 * Handles the redirect from the authorization server.
 * Extracts code and state, validates state, and exchanges code for tokens.
 */
async function handleAuthRedirect() {
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get("code");
    const state = urlParams.get("state");
    const error = urlParams.get("error");
    const errorDescription = urlParams.get("error_description");

    if (error) {
        displayMessage(`Authorization Error: ${error} - ${errorDescription}`, "error");
        return;
    }

    if (code && state) {
        const storedState = sessionStorage.getItem("oauth_state");
        if (state !== storedState) {
            displayMessage("State mismatch! Possible CSRF attack.", "error");
            return;
        }
        sessionStorage.removeItem("oauth_state"); // Clear state after validation

        const codeVerifier = sessionStorage.getItem("pkce_code_verifier");
        if (!codeVerifier) {
            displayMessage("Code Verifier not found in session storage.", "error");
            return;
        }
        sessionStorage.removeItem("pkce_code_verifier"); // Clear verifier after use

        try {
            await exchangeCodeForTokens(code, codeVerifier);
            // Clear the code and state from the URL history
            window.history.replaceState({}, document.title, window.location.pathname);
            updateUI();
        } catch (e) {
            displayMessage(`Token exchange failed: ${e.message}`, "error");
        }
    }
}

/**
 * Exchanges the authorization code for access and refresh tokens.
 * @param {string} code - The authorization code received from the authorization server.
 * @param {string} codeVerifier - The PKCE code verifier.
 */
async function exchangeCodeForTokens(code, codeVerifier) {
    const params = new URLSearchParams({
        grant_type: "authorization_code",
        client_id: oauthConfig.clientId,
        code: code,
        redirect_uri: oauthConfig.redirectUri,
        code_verifier: codeVerifier,
    });

    const response = await fetch(oauthConfig.tokenEndpoint, {
        method: "POST",
        headers: {
            "Content-Type": "application/x-www-form-urlencoded",
        },
        body: params.toString(),
    });

    if (!response.ok) {
        const errorData = await response.json();
        throw new Error(`HTTP error! status: ${response.status}, Error: ${errorData.error_description || errorData.error}`);
    }

    const tokenResponse = await response.json();
    storeTokens(tokenResponse);
}

/**
 * Stores the received tokens (access_token, refresh_token) and their expiry in localStorage.
 * @param {object} tokenResponse - The token response from the authorization server.
 */
function storeTokens(tokenResponse) {
    const { access_token, refresh_token, expires_in, id_token } = tokenResponse;

    if (access_token) {
        localStorage.setItem("access_token", access_token);
        // Calculate expiry time (current time + expires_in seconds)
        const expiresAt = Date.now() + (expires_in * 1000);
        localStorage.setItem("expires_at", expiresAt.toString());
    }
    if (refresh_token) {
        localStorage.setItem("refresh_token", refresh_token);
    }
    if (id_token) {
        localStorage.setItem("id_token", id_token); // Store ID Token if present
    }
    displayMessage("Tokens stored successfully!", "success");
    displayTokens();
}

/**
 * Retrieves the stored access token.
 * @returns {string|null} The access token, or null if not found or expired.
 */
function getAccessToken() {
    const accessToken = localStorage.getItem("access_token");
    const expiresAt = localStorage.getItem("expires_at");

    if (!accessToken || !expiresAt) {
        return null;
    }

    // Check if token is expired
    if (Date.now() >= parseInt(expiresAt, 10)) {
        displayMessage("Access token expired.", "warn");
        // Optionally, implement refresh token logic here
        // For simplicity, we'll just return null for now.
        // If a refresh token is present, you'd call `refreshAccessToken()` here.
        return null;
    }

    return accessToken;
}

/**
 * Uses the stored refresh token to obtain a new access token.
 * (Optional, but recommended for long-lived sessions)
 */
async function refreshAccessToken() {
    const refreshToken = localStorage.getItem("refresh_token");

    if (!refreshToken) {
        displayMessage("No refresh token available.", "error");
        return null;
    }

    const params = new URLSearchParams({
        grant_type: "refresh_token",
        client_id: oauthConfig.clientId,
        refresh_token: refreshToken,
    });

    try {
        const response = await fetch(oauthConfig.tokenEndpoint, {
            method: "POST",
            headers: {
                "Content-Type": "application/x-www-form-urlencoded",
            },
            body: params.toString(),
        });

        if (!response.ok) {
            const errorData = await response.json();
            throw new Error(`HTTP error! status: ${response.status}, Error: ${errorData.error_description || errorData.error}`);
        }

        const tokenResponse = await response.json();
        storeTokens(tokenResponse); // Store new access token and potentially new refresh token
        displayMessage("Access token refreshed!", "success");
        return tokenResponse.access_token;
    } catch (e) {
        displayMessage(`Failed to refresh token: ${e.message}`, "error");
        logout(); // Clear tokens if refresh fails
        return null;
    }
}

/**
 * Example function to fetch a protected resource using the access token.
 */
async function fetchProtectedResource() {
    let accessToken = getAccessToken();

    // If access token is expired and refresh token is available, try to refresh
    if (!accessToken && localStorage.getItem("refresh_token")) {
        accessToken = await refreshAccessToken();
    }

    if (!accessToken) {
        displayMessage("No valid access token available. Please log in.", "error");
        return;
    }

    // Replace with your actual protected API endpoint
    const protectedApiEndpoint = "https://your-api.com/protected";

    try {
        const response = await fetch(protectedApiEndpoint, {
            method: "GET",
            headers: {
                "Authorization": `Bearer ${accessToken}`,
                "Content-Type": "application/json",
            },
        });

        if (!response.ok) {
            // Handle 401 Unauthorized specifically
            if (response.status === 401) {
                displayMessage("Access denied (401). Token might be invalid or expired. Trying refresh...", "warn");
                // Attempt to refresh token and retry the request
                const newAccessToken = await refreshAccessToken();
                if (newAccessToken) {
                    // Retry request with new token
                    const retryResponse = await fetch(protectedApiEndpoint, {
                        method: "GET",
                        headers: {
                            "Authorization": `Bearer ${newAccessToken}`,
                            "Content-Type": "application/json",
                        },
                    });
                    if (retryResponse.ok) {
                        const data = await retryResponse.json();
                        displayMessage("Protected resource fetched successfully after refresh!", "success");
                        displayData(JSON.stringify(data, null, 2), "apiResponse");
                        return;
                    }
                }
                displayMessage("Failed to fetch resource even after token refresh. Please log in again.", "error");
                logout(); // Log out if refresh also fails or doesn't yield a valid token
                return;
            }
            throw new Error(`HTTP error! status: ${response.status}`);
        }

        const data = await response.json();
        displayMessage("Protected resource fetched successfully!", "success");
        displayData(JSON.stringify(data, null, 2), "apiResponse");
    } catch (e) {
        displayMessage(`Failed to fetch protected resource: ${e.message}`, "error");
    }
}

/**
 * Clears all stored tokens and updates the UI.
 */
function logout() {
    localStorage.removeItem("access_token");
    localStorage.removeItem("refresh_token");
    localStorage.removeItem("id_token");
    localStorage.removeItem("expires_at");
    displayMessage("Logged out successfully.", "info");
    updateUI();
}

// --- UI Management ---

function displayMessage(message, type = "info") {
    const messagesDiv = document.getElementById("messages");
    if (messagesDiv) {
        const p = document.createElement("p");
        p.className = `message message-${type}`;
        p.textContent = message;
        messagesDiv.appendChild(p);
        // Automatically clear messages after a few seconds
        setTimeout(() => p.remove(), 5000);
    }
}

function displayTokens() {
    const accessToken = localStorage.getItem("access_token");
    const refreshToken = localStorage.getItem("refresh_token");
    const idToken = localStorage.getItem("id_token");
    const expiresAt = localStorage.getItem("expires_at");

    displayData(accessToken || "N/A", "accessTokenDisplay");
    displayData(refreshToken || "N/A", "refreshTokenDisplay");
    displayData(idToken || "N/A", "idTokenDisplay");

    if (expiresAt && accessToken) {
        const expiryDate = new Date(parseInt(expiresAt, 10));
        const expiresInMs = parseInt(expiresAt, 10) - Date.now();
        const expiresInSeconds = Math.max(0, Math.round(expiresInMs / 1000));
        displayData(`Expires in: ${expiresInSeconds} seconds (${expiryDate.toLocaleString()})`, "expiresAtDisplay");
    } else {
        displayData("N/A", "expiresAtDisplay");
    }
}

function displayData(data, elementId) {
    const element = document.getElementById(elementId);
    if (element) {
        element.textContent = data;
    }
}

function updateUI() {
    const accessToken = getAccessToken(); // Checks for expiry too
    const isLoggedIn = !!accessToken;

    document.getElementById("loginBtn").style.display = isLoggedIn ? "none" : "block";
    document.getElementById("logoutBtn").style.display = isLoggedIn ? "block" : "none";
    document.getElementById("fetchProtectedBtn").style.display = isLoggedIn ? "block" : "none";
    document.getElementById("refreshTokenBtn").style.display = localStorage.getItem("refresh_token") ? "block" : "none";

    if (!isLoggedIn) {
        displayData("N/A", "accessTokenDisplay");
        displayData("N/A", "refreshTokenDisplay");
        displayData("N/A", "idTokenDisplay");
        displayData("N/A", "expiresAtDisplay");
        displayData("N/A", "apiResponse");
    } else {
        displayTokens();
    }
}

// --- Initialization ---

/**
 * Initializes the SPA logic on page load.
 * Checks for authorization codes in the URL and handles them.
 */
async function initApp() {
    // Attach event listeners
    document.getElementById("loginBtn").addEventListener("click", login);
    document.getElementById("logoutBtn").addEventListener("click", logout);
    document.getElementById("fetchProtectedBtn").addEventListener("click", fetchProtectedResource);
    document.getElementById("refreshTokenBtn").addEventListener("click", refreshAccessToken);

    const urlParams = new URLSearchParams(window.location.search);
    if (urlParams.has("code") || urlParams.has("error")) {
        await handleAuthRedirect();
    }
    updateUI();
}

// Ensure DOM is fully loaded before running init
document.addEventListener("DOMContentLoaded", initApp);

